sql:
SELECT vehicle_id, make_id, model_id, sale_price
FROM vehicles
WHERE vehicle_id = 0;

SELECT vehicle_id, make_id, model_id, year, color_id, vin, mileage, msrp, sale_price, last_inspection_date, location_id, status
FROM vehicles
WHERE is_certified = 1 AND sale_price > msrp;

SELECT 
    (SELECT SUM(CASE WHEN is_display = 1 THEN 1 ELSE 0 END) FROM inventory) AS total_inventory,
    (SELECT SUM(sale_price) FROM sales) AS total_sale_price;

SELECT COUNT(*) AS certified_count
FROM vehicles
WHERE is_certified = 1;

SELECT vehicle_id, image_file, image_date
FROM vehicle_images
ORDER BY image_date DESC;

SELECT COUNT(*) 
FROM vehicle_features_map
WHERE added_date LIKE '2023-05-%';

external_knowledge:
- 'Luxury speedsters' refers to high-end vehicles; 
- 'broke the 20,000-dollar barrier' means sale price > 20,000; 
- 'born after 2010' means the vehicle's year of manufacture is greater than 2010.

